  1	import * as React from 'react';
  2	
  3	import {
  4	  Chart,
  5	  ChartAxis,
  6	  ChartBar,
  7	  ChartGroup,
  8	  ChartLabel,
  9	  ChartLegend,
 10	  ChartThemeColor,
 11	  ChartTooltip,
 12	  ChartVoronoiContainer,
 13	} from '@patternfly/react-charts/victory';
 14	import { Bullseye, Card, CardTitle, Spinner } from '@patternfly/react-core';
 15	import { createIncidentsChartBars, formatDate, generateDateArray } from '../utils';
 16	import { getResizeObserver } from '@patternfly/react-core';
 17	import { useDispatch, useSelector } from 'react-redux';
 18	import { setChooseIncident } from '../../../actions/observe';
 19	import t_global_color_status_danger_default from '@patternfly/react-tokens/dist/esm/t_global_color_status_danger_default';
 20	import t_global_color_status_info_default from '@patternfly/react-tokens/dist/esm/t_global_color_status_info_default';
 21	import t_global_color_status_warning_default from '@patternfly/react-tokens/dist/esm/t_global_color_status_warning_default';
 22	import { setAlertsAreLoading } from '../../../actions/observe';
 23	
 24	const IncidentsChart = ({ incidentsData, chartDays, theme }) => {
 25	  const dispatch = useDispatch();
 26	  const [isLoading, setIsLoading] = React.useState(true);
 27	  const [chartData, setChartData] = React.useState();
 28	  const [chartContainerHeight, setChartContainerHeight] = React.useState();
 29	  const [chartHeight, setChartHeight] = React.useState();
 30	  React.useEffect(() => {
 31	    setChartContainerHeight(chartData?.length < 5 ? 300 : chartData?.length * 60);
 32	    setChartHeight(chartData?.length < 5 ? 250 : chartData?.length * 55);
 33	  }, [chartData]);
 34	  const [width, setWidth] = React.useState(0);
 35	  const containerRef = React.useRef(null);
 36	  const handleResize = () => {
 37	    if (containerRef.current && containerRef.current.clientWidth) {
 38	      setWidth(containerRef.current.clientWidth);
 39	    }
 40	  };
 41	  React.useEffect(() => {
 42	    const observer = getResizeObserver(containerRef.current, handleResize);
 43	    handleResize();
 44	    return () => observer();
 45	  }, []);
 46	  React.useEffect(() => {
 47	    setIsLoading(false);
 48	    setChartData(
 49	      incidentsData.map((incident) => createIncidentsChartBars(incident, theme, dateValues)),
 50	    );
 51	  }, [incidentsData]);
 52	  const dateValues = generateDateArray(chartDays);
 53	
 54	  const selectedId = useSelector((state) =>
 55	    state.plugins.mcp.getIn(['incidentsData', 'incidentGroupId']),
 56	  );
 57	
 58	  const isHidden = (group_id) => selectedId !== '' && selectedId !== group_id;
 59	  const clickHandler = (data, datum) => {
 60	    if (datum.datum.group_id === selectedId) {
 61	      dispatch(
 62	        setChooseIncident({
 63	          incidentGroupId: '',
 64	        }),
 65	      );
 66	      dispatch(setAlertsAreLoading({ alertsAreLoading: true }));
 67	    } else {
 68	      dispatch(
 69	        setChooseIncident({
 70	          incidentGroupId: datum.datum.group_id,
 71	        }),
 72	      );
 73	    }
 74	  };
 75	
 76	  function getOpacity(datum) {
 77	    return (datum.fillOpacity = isHidden(datum.group_id) ? '0.3' : '1');
 78	  }
 79	
 80	  return (
 81	    <Card className="incidents-chart-card">
 82	      <div ref={containerRef}>
 83	        <CardTitle>Incidents Timeline</CardTitle>
 84	        {isLoading ? (
 85	          <Bullseye>
 86	            <Spinner aria-label="incidents-chart-spinner" />
 87	          </Bullseye>
 88	        ) : (
 89	          <div
 90	            style={{
 91	              height: { chartContainerHeight },
 92	              width: '100%',
 93	            }}
 94	          >
 95	            <Chart
 96	              containerComponent={
 97	                <ChartVoronoiContainer
 98	                  labelComponent={
 99	                    <ChartTooltip
100	                      orientation="top"
101	                      constrainToVisibleArea
102	                      labelComponent={<ChartLabel />}
103	                    />
104	                  }
105	                  labels={({ datum }) => {
106	                    if (datum.nodata) {
107	                      return null;
108	                    }
109	                    return `Severity: ${datum.name}
110	                    Component: ${datum.componentList?.join(', ')}
111	                    Incident ID: ${datum.group_id}
112	                    Start: ${formatDate(new Date(datum.y0), true)}
113	                    End: ${datum.firing ? '---' : formatDate(new Date(datum.y), true)}`;
114	                  }}
115	                />
116	              }
117	              domainPadding={{ x: [30, 25] }}
118	              legendData={[
119	                {
120	                  name: 'Critical',
121	                  symbol: {
122	                    fill: theme === 'light' ? t_global_color_status_danger_default.var : '#C9190B',
123	                  },
124	                },
125	                {
126	                  name: 'Info',
127	                  symbol: {
128	                    fill: theme === 'light' ? t_global_color_status_info_default.var : '#06C',
129	                  },
130	                },
131	                {
132	                  name: 'Warning',
133	                  symbol: {
134	                    fill: theme === 'light' ? t_global_color_status_warning_default.var : '#F0AB00',
135	                  },
136	                },
137	              ]}
138	              legendComponent={
139	                <ChartLegend
140	                  labelComponent={
141	                    <ChartLabel style={{ fill: theme === 'light' ? '#1b1d21' : '#e0e0e0' }} />
142	                  }
143	                />
144	              }
145	              legendPosition="bottom-left"
146	              //this should be always less than the container height
147	              height={chartHeight}
148	              padding={{
149	                bottom: 75, // Adjusted to accommodate legend
150	                left: 50,
151	                right: 25, // Adjusted to accommodate tooltip
152	                top: 50,
153	              }}
154	              width={width}
155	              themeColor={ChartThemeColor.purple}
156	            >
157	              <ChartAxis
158	                dependentAxis
159	                showGrid
160	                tickFormat={(t) =>
161	                  new Date(t).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })
162	                }
163	                tickValues={dateValues}
164	                tickLabelComponent={
165	                  <ChartLabel style={{ fill: theme === 'light' ? '#1b1d21' : '#e0e0e0' }} />
166	                }
167	              />
168	              <ChartGroup horizontal>
169	                {chartData.map((bar) => {
170	                  return (
171	                    //we have several arrays and for each array we make a ChartBar
172	                    <ChartBar
173	                      data={bar}
174	                      key={bar.group_id}
175	                      style={{
176	                        data: {
177	                          fill: ({ datum }) => datum.fill,
178	                          stroke: ({ datum }) => datum.fill,
179	                          fillOpacity: ({ datum }) => (datum.nodata ? 0 : getOpacity(datum)),
180	                        },
181	                      }}
182	                      events={[
183	                        {
184	                          eventHandlers: {
185	                            onClick: (props, datum) => clickHandler(props, datum),
186	                          },
187	                        },
188	                      ]}
189	                    />
190	                  );
191	                })}
192	              </ChartGroup>
193	            </Chart>
194	          </div>
195	        )}
196	      </div>
197	    </Card>
198	  );
199	};
200	
201	export default IncidentsChart;

